mapper.select:
SELECT * FROM(
SELECT ROW_NUMBER() OVER(ORDER BY member_idx DESC) AS rnum, a.*
FROM(
SELECT * FROM member
WHERE member_type = 1
ORDER BY member_idx DESC
) a
) c WHERE c.rnum BETWEEN #{begin} AND #{end}

mapper.update:
UPDATE member
member_name = #{member_name}, member_nickname = #{member_nickname}, member_password = #{member_password}, member_email = #{member_email}, member_id = #{member_id}
WHERE member_idx = #{member_idx}

mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY member_idx DESC) AS rnum, member_idx, member_id, member_name, member_nickname, member_warning, member_type FROM member
member_id LIKE CONCAT ('%', #{searchValue}, '%')
member_name LIKE CONCAT('%', #{searchValue}, '%')
member_nickname LIKE CONCAT('%', #{searchValue}, '%')
member_warning = #{searchValue}
AND member_status = 0 AND member_type = 1
)a where a.rnum BETWEEN #{begin} AND #{end};
